prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?sourceName ?targetName ?edgeName WHERE {
  ?edge a bbo:SequenceFlow .
  ?edge tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_a91555f6_d70d_4c6b_b0ad_d70ef853da6e> .
  ?edge bbo:has_sourceRef ?source .
  ?edge bbo:has_targetRef ?target .
  OPTIONAL { ?source bbo:name ?sourceName . }
  OPTIONAL { ?target bbo:name ?targetName . }
  OPTIONAL { ?edge bbo:name ?edgeName . }
}
LIMIT 50

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?taskName ?loopType WHERE {
  ?task a bboExt:ChoreographyTask .
  ?task tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_a91555f6_d70d_4c6b_b0ad_d70ef853da6e> .
  OPTIONAL { ?task bbo:name ?taskName . }
  OPTIONAL { ?task bboExt:loopType ?loopType . }
  FILTER(?loopType != "None" || ?loopType = "Standard" || ?loopType = "MultiInstanceSequential" || ?loopType = "MultiInstanceParallel")
}
